+import React, { useState, useEffect } from 'react';
+import api from '../utils/api';
+import toast from 'react-hot-toast';
+import { FiEdit2, FiTrash2, FiPlus, FiSearch } from 'react-icons/fi';
+
+const getProductImage = (category) => {
+  // نفس دالة الصور السابقة
+  const images = {
+    'Dairy': 'https://images.unsplash.com/photo-1550583724-b2692b5b2b4f?w=100&h=100&fit=crop',
+    'Bakery': 'https://images.unsplash.com/photo-1509440159596-0249088772ff?w=100&h=100&fit=crop',
+    'Beverages': 'https://images.unsplash.com/photo-1543253687-c931c8e01820?w=100&h=100&fit=crop',
+    'Fruits': 'https://images.unsplash.com/photo-1619566636858-adf3ef46400b?w=100&h=100&fit=crop',
+    'Vegetables': 'https://images.unsplash.com/photo-1597362921503-75c3da9e4feb?w=100&h=100&fit=crop',
+    'Meat': 'https://images.unsplash.com/photo-1607623814075-e51df1bdc82f?w=100&h=100&fit=crop',
+    'Snacks': 'https://images.unsplash.com/photo-1621939514649-280e2ee25f60?w=100&h=100&fit=crop',
+    'Grains': 'https://images.unsplash.com/photo-1586201375761-83865001e31c?w=100&h=100&fit=crop'
+  };
+  return images[category] || 'https://images.unsplash.com/photo-1542838132-92c53300491e?w=100&h=100&fit=crop';
+};
+
+const ProductManagement = () => {
+  const [products, setProducts] = useState([]);
+  const [search, setSearch] = useState('');
+  const [showModal, setShowModal] = useState(false);
+  const [editingProduct, setEditingProduct] = useState(null);
+  const [formData, setFormData] = useState({
+    name: '', barcode: '', category: '', selling_price: '', cost_price: '', stock: '', min_stock: '5'
+  });
+
+  useEffect(() => {
+    fetchProducts();
+  }, []);
+
+  const fetchProducts = async () => {
+    try {
+      const res = await api.get('/products');
+      const withImages = res.data.map(p => ({ ...p, image: getProductImage(p.category) }));
+      setProducts(withImages);
+    } catch (error) {
+      toast.error('Failed to load products');
+    }
+  };
+
+  const handleSearch = async () => {
+    if (!search.trim()) {
+      fetchProducts();
+      return;
+    }
+    try {
+      const res = await api.get(`/products?search=${search}`);
+      const withImages = res.data.map(p => ({ ...p, image: getProductImage(p.category) }));
+      setProducts(withImages);
+    } catch (error) {
+      toast.error('Search failed');
+    }
+  };
+
+  const resetForm = () => {
+    setFormData({ name: '', barcode: '', category: '', selling_price: '', cost_price: '', stock: '', min_stock: '5' });
+    setEditingProduct(null);
+  };
+
+  const handleSubmit = async (e) => {
+    e.preventDefault();
+    try {
+      if (editingProduct) {
+        await api.put(`/products/${editingProduct.id}`, formData);
+        toast.success('Product updated');
+      } else {
+        await api.post('/products', formData);
+        toast.success('Product added');
+      }
+      setShowModal(false);
+      resetForm();
+      fetchProducts();
+    } catch (error) {
+      toast.error(editingProduct ? 'Update failed' : 'Add failed');
+    }
+  };
+
+  const handleEdit = (product) => {
+    setEditingProduct(product);
+    setFormData(product);
+    setShowModal(true);
+  };
+
+  const handleDelete = async (id) => {
+    if (window.confirm('Are you sure?')) {
+      try {
+        await api.delete(`/products/${id}`);
+        toast.success('Deleted');
+        fetchProducts();
+      } catch (error) {
+        toast.error('Delete failed');
+      }
+    }
+  };
+
+  return (
+    <div className="space-y-6">
+      <div className="flex justify-between items-center">
+        <h1 className="text-2xl font-bold text-gray-800">Products</h1>
+        <button
+          onClick={() => { resetForm(); setShowModal(true); }}
+          className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg font-medium flex items-center gap-2"
+        >
+          <FiPlus /> Add Product
+        </button>
+      </div>
+
+      <div className="flex gap-2">
+        <div className="relative flex-1">
+          <FiSearch className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
+          <input
+            type="text"
+            placeholder="Search by name or barcode..."
+            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500"
+            value={search}
+            onChange={(e) => setSearch(e.target.value)}
+            onKeyPress={(e) => e.key === 'Enter' && handleSearch()}
+          />
+        </div>
+        <button onClick={handleSearch} className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700">Search</button>
+      </div>
+
+      <div className="bg-white rounded-xl shadow-md overflow-hidden">
+        <div className="overflow-x-auto">
+          <table className="min-w-full">
+            <thead className="bg-gray-50">
+              <tr>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Image</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Name</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Barcode</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Price</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Stock</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Category</th>
+                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Actions</th>
+              </tr>
+            </thead>
+            <tbody className="divide-y divide-gray-200">
+              {products.map(p => (
+                <tr key={p.id} className="hover:bg-gray-50">
+                  <td className="px-6 py-4">
+                    <img src={p.image} alt={p.name} className="w-10 h-10 rounded-lg object-cover" />
+                  </td>
+                  <td className="px-6 py-4 font-medium">{p.name}</td>
+                  <td className="px-6 py-4 text-gray-600">{p.barcode}</td>
+                  <td className="px-6 py-4 text-green-600 font-semibold">${p.selling_price}</td>
+                  <td className="px-6 py-4">{p.stock}</td>
+                  <td className="px-6 py-4">{p.category || '—'}</td>
+                  <td className="px-6 py-4">
+                    <div className="flex gap-2">
+                      <button onClick={() => handleEdit(p)} className="text-blue-600 hover:text-blue-800">
+                        <FiEdit2 size={18} />
+                      </button>
+                      <button onClick={() => handleDelete(p.id)} className="text-red-600 hover:text-red-800">
+                        <FiTrash2 size={18} />
+                      </button>
+                    </div>
+                  </td>
+                </tr>
+              ))}
+            </tbody>
+          </table>
+        </div>
+      </div>
+
+      {/* Modal for add/edit */}
+      {showModal && (/* نفس المحتوى السابق مع إضافة حقل الصورة اختياري */) }
+    </div>
+  );
+};
+
+export default ProductManagement;
